   354→// Run wires up subscriptions and blocks until ctx is cancelled.
   355→// It spawns two goroutines:
   356→//   1. eventLoop:   consumes incoming SocialEvents
   357→//   2. windowLoop:  periodically evaluates completed windows
   358→func (s *CommunityScorer) Run(ctx context.Context, topicIn, topicOut string) error {
   359→	evtCh, err := s.sub.Subscribe(ctx, topicIn)
   360→	if err != nil {
   361→		return err
   362→	}
   363→
   364→	// Using errgroup ensures both goroutines finish cleanly.
   365→	var wg sync.WaitGroup
   366→	wg.Add(2)
