   368→	go func() {
   369→		defer wg.Done()
   370→		s.eventLoop(ctx, evtCh)
   371→	}()
   372→
   373→	go func() {
   374→		defer wg.Done()
   375→		s.windowLoop(ctx, topicOut)
   376→	}()
   377→
   378→	<-ctx.Done()
