   391→	if s.cfg.PublishPartialWindows {
   392→		now := time.Now().UTC()
   393→		windows := s.aggregator.popWindows(now.Add(s.cfg.WindowSize))
   394→		for _, w := range windows {
   395→			_ = s.processWindow(ctx, topicOut, w.evts) // best effort
   396→		}
   397→	}
   398→
   399→	return nil
   400→}
