   402→// eventLoop ingests events and feeds them to the aggregator.
   403→func (s *CommunityScorer) eventLoop(ctx context.Context, evtCh <-chan SocialEvent) {
   404→	for {
   405→		select {
   406→		case <-ctx.Done():
   407→			return
   408→		case evt, ok := <-evtCh:
   409→			if !ok {
   410→				return
   411→			}
   412→			s.metrics.incomingEvents.Inc()
   413→			s.aggregator.addEvent(evt)
   414→		}
   415→	}
   416→}
   417→
   418→// windowLoop periodically asks the aggregator for completed windows.
   419→func (s *CommunityScorer) windowLoop(ctx context.Context, topicOut string) {
   420→	ticker := time.NewTicker(s.cfg.WindowSlide)
   421→	defer ticker.Stop()
   422→
   423→	for {
   424→		select {
   425→		case <-ctx.Done():
   426→			return
   427→		case ts := <-ticker.C:
   428→			windows := s.aggregator.popWindows(ts)
   429→			for _, w := range windows {
   430→				start := time.Now()
   431→				if err := s.processWindow(ctx, topicOut, w.evts); err != nil {
   432→					s.metrics.strategyFailures.Inc()
   433→				}
