   435→			}
   436→		}
   437→	}
   438→}
   439→
   440→// processWindow applies the strategy and publishes the score.
   441→func (s *CommunityScorer) processWindow(ctx context.Context, topicOut string, events []SocialEvent) error {
   442→	scoreVal, err := s.strategy.Compute(events)
   443→	if err != nil {
   444→		return err
   445→	}
   446→
   447→	// We create one HealthScore per channel.
   448→	perChannel := make(map[string][]SocialEvent)
   449→	for _, e := range events {
   450→		perChannel[e.ChannelID] = append(perChannel[e.ChannelID], e)
   451→	}
   452→
   453→	for chID, evts := range perChannel {
   454→		scoreVal, err = s.strategy.Compute(evts)
   455→		if err != nil {
   456→			return err
   457→		}
   458→		score := HealthScore{
   459→			ChannelID: chID,
   460→			Score:     scoreVal,
   461→			Timestamp: time.Now().UTC(),
   462→			Version:   s.strategy.Version(),
   463→		}
   464→		if err := s.pub.Publish(ctx, topicOut, score); err != nil {
   465→			return err
   466→		}
   467→		s.metrics.publishedScores.Inc()
   468→	}
   469→	return nil
   470→}
