    36→
    37→// ========================= Domain Objects ================================
    38→
    39→// SocialEvent is the canonical unit emitted by upstream ingestion pipelines.
    40→type SocialEvent struct {
    41→	ID        string            `json:"id"`
    42→	Timestamp time.Time         `json:"ts"`
    43→	Text      string            `json:"text"`
    44→	Metadata  map[string]string `json:"meta,omitempty"`
    45→	Priority  int               `json:"priority"` // 0 == best-effort, larger == more important
    46→}
    47→
    48→// Prediction is the result of running an ML model against a SocialEvent.
    49→type Prediction struct {
    50→	EventID   string    `json:"event_id"`
    51→	Sentiment float64   `json:"sentiment"` // (−1 .. 1)
    52→	ModelName string    `json:"model"`
    53→	Latency   time.Duration
    54→	CreatedAt time.Time `json:"ts"`
    55→}
    56→
    57→// ========================= Observer Pattern ==============================
    58→
    59→// Observer receives Predictions.
    60→type Observer interface {
    61→	Notify(Prediction)
    62→}
    63→
    64→// ObserverFunc is a functional adapter so ordinary funcs can be observers.
    65→type ObserverFunc func(Prediction)
    66→
    67→func (f ObserverFunc) Notify(p Prediction) { f(p) }
    68→
    69→// ========================= Model Registry ===============================
    70→
    71→// ModelRegistry knows how to resolve logical model names to runnable endpoints.
    72→type ModelRegistry interface {
    73→	Resolve(ctx context.Context, name, version string) (Endpoint, error)
    74→}
    75→
    76→// Endpoint describes how a model can be reached.
    77→type Endpoint struct {
    78→	HostPort string // host:port of the gRPC model server
    79→	Timeout  time.Duration
    80→}
    81→
    82→// simpleRegistry is a toy in-memory registry.
    83→type simpleRegistry struct {
    84→	mu   sync.RWMutex
    85→	data map[string]Endpoint
    86→}
    87→
    88→func NewSimpleRegistry() *simpleRegistry {
    89→	return &simpleRegistry{data: make(map[string]Endpoint)}
    90→}
    91→
    92→func (r *simpleRegistry) Register(name, version, hostport string, timeout time.Duration) {
    93→	r.mu.Lock()
    94→	defer r.mu.Unlock()
    95→	key := fmt.Sprintf("%s:%s", name, version)
    96→	r.data[key] = Endpoint{HostPort: hostport, Timeout: timeout}
    97→}
    98→
    99→func (r *simpleRegistry) Resolve(ctx context.Context, name, version string) (Endpoint, error) {
   100→	r.mu.RLock()
   101→	defer r.mu.RUnlock()
   102→	key := fmt.Sprintf("%s:%s", name, version)
   103→	ep, ok := r.data[key]
   104→	if !ok {
   105→		return Endpoint{}, errors.New("model not found in registry")
   106→	}
   107→	return ep, nil
   108→}
   109→
   110→// ========================= Model Client =================================
   111→
   112→// ModelClient hides transport-level details and exposes a stateless Predict call.
   113→type ModelClient interface {
   114→	Predict(ctx context.Context, text string) (float64, error)
   115→	Close() error
   116→}
   117→
   118→type grpcModelClient struct {
   119→	cc       *grpc.ClientConn
   120→	model    string
   121→	latency  time.Duration // artificial latency for the demo
   122→	failRate float64       // chance to cause an error
   123→}
   124→
   125→func newGRPCModelClient(model string, ep Endpoint) (*grpcModelClient, error) {
   126→	ctx, cancel := context.WithTimeout(context.Background(), ep.Timeout)
   127→	defer cancel()
   128→	conn, err := grpc.DialContext(ctx, ep.HostPort, grpc.WithInsecure(), grpc.WithBlock())
   129→	if err != nil {
   130→		return nil, err
   131→	}
   132→	return &grpcModelClient{
   133→		cc:       conn,
   134→		model:    model,
   135→		latency:  time.Millisecond * time.Duration(rand.Intn(20)+5),
   136→		failRate: 0.05, // 5% simulated failure
   137→	}, nil
   138→}
   139→
   140→func (c *grpcModelClient) Predict(ctx context.Context, text string) (float64, error) {
   141→	if rand.Float64() < c.failRate {
   142→		return 0, errors.New("simulated inference failure")
   143→	}
   144→	select {
   145→	case <-time.After(c.latency):
   146→		// Fake deterministic sentiment for the demo.
   147→		hash := 0
   148→		for _, r := range text {
   149→			hash += int(r)
   150→		}
   151→		sentiment := (float64(hash%200) / 100.0) - 1.0 // −1 .. +1
   152→		return sentiment, nil
   153→	case <-ctx.Done():
   154→		return 0, ctx.Err()
   155→	}
   156→}
   157→
   158→func (c *grpcModelClient) Close() error { return c.cc.Close() }
   159→
   160→// ========================= Strategy Pattern =============================
   161→
   162→// PredictorStrategy chooses an implementation at runtime.
   163→type PredictorStrategy interface {
   164→	Predict(ctx context.Context, ev SocialEvent) (Prediction, error)
   165→}
   166→
   167→// highAccuracyStrategy may be slower but more accurate.
   168→type highAccuracyStrategy struct {
   169→	client ModelClient
   170→	model  string
   171→}
   172→
   173→func (s *highAccuracyStrategy) Predict(ctx context.Context, ev SocialEvent) (Prediction, error) {
   174→	start := time.Now()
   175→	val, err := s.client.Predict(ctx, ev.Text)
   176→	if err != nil {
   177→		return Prediction{}, err
   178→	}
   179→	return Prediction{
   180→		EventID:   ev.ID,
   181→		Sentiment: val,
   182→		ModelName: s.model,
   183→		Latency:   time.Since(start),
   184→		CreatedAt: time.Now(),
   185→	}, nil
   186→}
   187→
   188→// lowLatencyStrategy returns a quick heuristic.
   189→type lowLatencyStrategy struct {
   190→	model string
   191→}
   192→
   193→func (s *lowLatencyStrategy) Predict(_ context.Context, ev SocialEvent) (Prediction, error) {
   194→	// Extremely naive bag-of-words approach for the demo.
   195→	words := 0
   196→	neg := 0
   197→	for _, tok := range []byte(ev.Text) {
   198→		if tok == ' ' {
   199→			words++
   200→		}
   201→		if tok == '!' || tok == '?' || tok == ':' {
   202→			neg++
   203→		}
   204→	}
   205→	sentiment := 1.0 - float64(neg)/float64(words+1) // crude heuristic
   206→	return Prediction{
   207→		EventID:   ev.ID,
   208→		Sentiment: sentiment,
   209→		ModelName: s.model,
   210→		Latency:   0,
   211→		CreatedAt: time.Now(),
   212→	}, nil
   213→}
