   215→// ========================= Router (Context Object) ======================
   216→
   217→// SentimentRouter routes events to an appropriate predictor then fans out
   218→// results to observers.  It encapsulates the Strategy & Observer patterns.
   219→type SentimentRouter struct {
   220→	workers       int
   221→	registry      ModelRegistry
   222→	obsMu         sync.RWMutex
   223→	observers     []Observer
   224→	eventCh       chan SocialEvent
   225→	ctx           context.Context
   226→	cancel        context.CancelFunc
   227→	wg            sync.WaitGroup
   228→	accClientOnce sync.Once
   229→	accClient     ModelClient // high-accuracy shared client
   230→}
   231→
   232→func NewSentimentRouter(workers int, registry ModelRegistry) *SentimentRouter {
   233→	if workers <= 0 {
   234→		workers = 4
   235→	}
   236→	ctx, cancel := context.WithCancel(context.Background())
   237→	return &SentimentRouter{
   238→		workers:  workers,
   239→		registry: registry,
   240→		eventCh:  make(chan SocialEvent, workers*2),
   241→		ctx:      ctx,
   242→		cancel:   cancel,
   243→	}
   244→}
   245→
   246→// Subscribe adds an observer that will receive Prediction notifications.
   247→func (r *SentimentRouter) Subscribe(obs Observer) {
   248→	r.obsMu.Lock()
   249→	defer r.obsMu.Unlock()
   250→	r.observers = append(r.observers, obs)
   251→}
   252→
   253→// Push queues an event for asynchronous processing.
   254→func (r *SentimentRouter) Push(ev SocialEvent) error {
   255→	select {
   256→	case r.eventCh <- ev:
   257→		return nil
   258→	case <-r.ctx.Done():
   259→		return r.ctx.Err()
   260→	}
   261→}
   262→
   263→// Start launches the worker pool.
   264→func (r *SentimentRouter) Start() {
   265→	r.wg.Add(r.workers)
   266→	for i := 0; i < r.workers; i++ {
   267→		go r.worker(i)
   268→	}
   269→}
   270→
   271→// Stop gracefully shuts down the router.
   272→func (r *SentimentRouter) Stop() {
   273→	r.cancel()
   274→	r.wg.Wait()
   275→	if r.accClient != nil {
   276→		_ = r.accClient.Close()
   277→	}
   278→	close(r.eventCh)
   279→}
   280→
   281→// ========================= Internal Helpers =============================
   282→
   283→func (r *SentimentRouter) worker(id int) {
   284→	defer r.wg.Done()
   285→	log.Printf("[router] worker #%d online", id)
   286→
   287→	for {
   288→		select {
   289→		case ev := <-r.eventCh:
   290→			r.processEvent(ev)
   291→		case <-r.ctx.Done():
   292→			return
   293→		}
   294→	}
   295→}
   296→
   297→func (r *SentimentRouter) processEvent(ev SocialEvent) {
   298→	ctx, cancel := context.WithTimeout(r.ctx, 500*time.Millisecond)
   299→	defer cancel()
   300→
   301→	var strat PredictorStrategy
   302→	// Simulated heuristics:
   303→	//   High-priority events -> high-accuracy model
   304→	//   Otherwise -> low-latency model
   305→	if ev.Priority > 5 {
   306→		client, err := r.getAccurateClient(ctx)
   307→		if err != nil {
   308→			log.Printf("[router] resolve err (%s): %v; falling back", ev.ID, err)
   309→			strat = &lowLatencyStrategy{model: "heuristic_v1"}
   310→		} else {
   311→			strat = &highAccuracyStrategy{
   312→				client: client,
   313→				model:  "bert-sentiment:10",
   314→			}
   315→		}
   316→	} else {
   317→		strat = &lowLatencyStrategy{model: "heuristic_v1"}
   318→	}
   319→
   320→	pred, err := strat.Predict(ctx, ev)
   321→	if err != nil {
   322→		log.Printf("[router] prediction failed (%s): %v", ev.ID, err)
   323→		return
   324→	}
   325→	r.notify(pred)
   326→}
   327→
   328→func (r *SentimentRouter) getAccurateClient(ctx context.Context) (ModelClient, error) {
   329→	var err error
   330→	r.accClientOnce.Do(func() {
   331→		ep, e := r.registry.Resolve(ctx, "bert-sentiment", "10")
   332→		if e != nil {
   333→			err = e
   334→			return
   335→		}
   336→		// If the model server isn't already running, spin up a local fake.
   337→		if ep.HostPort == "inproc" {
   338→			ep.HostPort, e = launchInprocModelServer()
   339→			if e != nil {
   340→				err = e
   341→				return
   342→			}
   343→		}
   344→		r.accClient, err = newGRPCModelClient("bert-sentiment:10", ep)
   345→	})
   346→	return r.accClient, err
   347→}
   348→
   349→func (r *SentimentRouter) notify(p Prediction) {
   350→	r.obsMu.RLock()
   351→	defer r.obsMu.RUnlock()
   352→	for _, o := range r.observers {
   353→		// Fan-out in a separate goroutine to avoid blocking slow observers.
   354→		go o.Notify(p)
   355→	}
   356→}
