     4→//
     5→// Module 72 – Streaming Feature-Drift Detector
     6→//
     7→// This component monitors a stream of feature vectors, continuously computing
     8→// Population-Stability-Index (PSI) scores against a reference distribution
     9→// kept in the feature-store.  When statistically significant drift is found
    10→// the detector publishes a DriftAlert event onto the event-bus so that the
    11→// automated retraining loop can kick in.
    12→//
    13→// Pattern palette:
    14→//   • Observer      – Kafka consumer group watching the feature topic
    15→//   • Strategy      – PSI (default) but pluggable detector interface
    16→//   • Pipeline      – Streaming window → aggregation → scoring → alerting
    17→//
    18→// The implementation is completely self-contained; external dependencies are
    19→// limited to Sarama (Kafka) and the standard library.
    20→
    21→package echopulse
    22→
    23→import (
    24→	"context"
    25→	"encoding/json"
    26→	"errors"
    27→	"fmt"
    28→	"log/slog"
    29→	"math"
    30→	"os"
    31→	"os/signal"
    32→	"sync"
    33→	"syscall"
    34→	"time"
