    40→// DriftDetectorConfig contains all runtime knobs for the detector.
    41→type DriftDetectorConfig struct {
    42→	BrokerURLs   []string                     // Kafka bootstrap servers
    43→	FeatureTopic string                       // Topic that carries feature vectors
    44→	AlertTopic   string                       // Topic to publish DriftAlert events
    45→	GroupID      string                       // Kafka consumer group
    46→	WindowSize   int                          // #observations per sliding window
    47→	PSIThreshold float64                      // Alert threshold
    48→	Reference    map[string]FeatureReference  // Pre-computed reference distributions
    49→	Logger       *slog.Logger                 // Optional structured logger
    50→}
    51→
    52→// FeatureReference holds a reference distribution for one feature.
    53→type FeatureReference struct {
    54→	Bins      []float64 `json:"bins"`       // Edges, monotonically increasing
    55→	Expected  []float64 `json:"expected"`   // Expected proportions (len = len(Bins)-1)
    56→}
    57→
    58→// DriftAlert is the event emitted when drift is detected.
    59→type DriftAlert struct {
    60→	Feature    string    `json:"feature"`
    61→	PSI        float64   `json:"psi"`
    62→	Threshold  float64   `json:"threshold"`
    63→	WindowSize int       `json:"window_size"`
    64→	Timestamp  time.Time `json:"timestamp"`
    65→}
    66→
    67→// detectorWindow keeps a sliding window of observations for one feature.
    68→type detectorWindow struct {
    69→	ref FeatureReference
    70→	mu  sync.Mutex
    71→	// counts len = len(ref.Expected)
    72→	counts []int
    73→	n      int // total count in window
    74→}
    75→
    76→func newDetectorWindow(ref FeatureReference) *detectorWindow {
    77→	return &detectorWindow{
    78→		ref:    ref,
    79→		counts: make([]int, len(ref.Expected)),
    80→	}
    81→}
    82→
    83→func (w *detectorWindow) add(v float64) {
    84→	w.mu.Lock()
    85→	defer w.mu.Unlock()
    86→
    87→	idx := binIndex(v, w.ref.Bins)
    88→	if idx < 0 || idx >= len(w.counts) {
    89→		// out of bounds → ignore but keep metrics consistent
    90→		return
    91→	}
    92→	w.counts[idx]++
    93→	w.n++
    94→}
    95→
    96→func (w *detectorWindow) ready(windowSize int) bool {
    97→	w.mu.Lock()
    98→	defer w.mu.Unlock()
    99→	return w.n >= windowSize
   100→}
   101→
   102→// pop returns counts and resets window.
   103→func (w *detectorWindow) pop() []int {
   104→	w.mu.Lock()
   105→	defer w.mu.Unlock()
   106→
   107→	out := make([]int, len(w.counts))
   108→	copy(out, w.counts)
   109→
   110→	// reset
   111→	for i := range w.counts {
   112→		w.counts[i] = 0
   113→	}
   114→	w.n = 0
   115→	return out
   116→}
