   126→// NewDriftDetector prepares a ready-to-run detector.
   127→func NewDriftDetector(cfg DriftDetectorConfig) (*DriftDetector, error) {
   128→	if cfg.WindowSize <= 0 {
   129→		return nil, errors.New("window size must be > 0")
   130→	}
   131→	if cfg.PSIThreshold <= 0 {
   132→		return nil, errors.New("PSI threshold must be > 0")
   133→	}
   134→	if len(cfg.Reference) == 0 {
   135→		return nil, errors.New("reference distributions cannot be empty")
   136→	}
   137→	if len(cfg.BrokerURLs) == 0 {
   138→		return nil, errors.New("at least one broker URL must be provided")
   139→	}
   140→
   141→	// Logger fallback
   142→	if cfg.Logger == nil {
   143→		cfg.Logger = slog.New(slog.NewJSONHandler(os.Stderr, nil))
   144→	}
   145→
   146→	prodCfg := sarama.NewConfig()
   147→	prodCfg.Producer.Return.Successes = false
   148→	prodCfg.Producer.RequiredAcks = sarama.WaitForLocal
   149→	prodCfg.Version = sarama.MaxVersion
   150→
   151→	prod, err := sarama.NewAsyncProducer(cfg.BrokerURLs, prodCfg)
   152→	if err != nil {
   153→		return nil, fmt.Errorf("create producer: %w", err)
   154→	}
   155→
   156→	w := make(map[string]*detectorWindow)
   157→	for fname, ref := range cfg.Reference {
   158→		if len(ref.Bins) < 2 || len(ref.Expected) != len(ref.Bins)-1 {
   159→			return nil, fmt.Errorf("invalid reference for feature %q", fname)
   160→		}
   161→		w[fname] = newDetectorWindow(ref)
   162→	}
   163→
   164→	return &DriftDetector{
   165→		conf:     cfg,
   166→		producer: prod,
   167→		windows:  w,
   168→		log:      cfg.Logger.With("component", "drift-detector"),
   169→	}, nil
   170→}
