   172→// Run blocks until ctx is canceled or a fatal error occurs.
   173→func (d *DriftDetector) Run(ctx context.Context) error {
   174→	grp, ctx := errgroup.WithContext(ctx)
   175→
   176→	// Graceful shutdown: surface producer errors
   177→	grp.Go(func() error {
   178→		for {
   179→			select {
   180→			case <-ctx.Done():
   181→				return ctx.Err()
   182→			case err := <-d.producer.Errors():
   183→				if err != nil {
   184→					d.log.Error("producer error", "err", err)
   185→				}
   186→			}
   187→		}
   188→	})
   189→
   190→	// Consumer group
   191→	grp.Go(func() error {
   192→		return d.consume(ctx)
   193→	})
   194→
   195→	// Wait for termination
   196→	err := grp.Wait()
   197→	_ = d.producer.Close()
   198→	return err
   199→}
