   201→// consume spins up a Sarama consumer group and processes messages.
   202→func (d *DriftDetector) consume(ctx context.Context) error {
   203→	cfg := sarama.NewConfig()
   204→	cfg.Version = sarama.MaxVersion
   205→	cfg.ClientID = "echopulse-drift-detector"
   206→	cfg.Consumer.Offsets.Initial = sarama.OffsetNewest
   207→	cfg.Consumer.Group.Rebalance.GroupStrategies = []sarama.BalanceStrategy{sarama.NewBalanceStrategyRange()}
   208→	cfg.Consumer.Group.Session.Timeout = 10 * time.Second
   209→
   210→	cg, err := sarama.NewConsumerGroup(d.conf.BrokerURLs, d.conf.GroupID, cfg)
   211→	if err != nil {
   212→		return fmt.Errorf("create consumer group: %w", err)
   213→	}
   214→	defer cg.Close()
   215→
   216→	handler := &featureConsumerGroupHandler{
   217→		ctx:      ctx,
   218→		detector: d,
   219→	}
   220→
   221→	for {
   222→		if err := cg.Consume(ctx, []string{d.conf.FeatureTopic}, handler); err != nil {
   223→			return fmt.Errorf("consume loop: %w", err)
   224→		}
   225→		if ctx.Err() != nil {
   226→			return ctx.Err()
   227→		}
   228→	}
   229→}
