   236→
   237→func (h *featureConsumerGroupHandler) Setup(_ sarama.ConsumerGroupSession) error   { return nil }
   238→func (h *featureConsumerGroupHandler) Cleanup(_ sarama.ConsumerGroupSession) error { return nil }
   239→func (h *featureConsumerGroupHandler) ConsumeClaim(sess sarama.ConsumerGroupSession, claim sarama.ConsumerGroupClaim) error {
   240→	for msg := range claim.Messages() {
   241→		select {
   242→		case <-h.ctx.Done():
