   255→// processMessage decodes a feature vector and updates windows.
   256→func (d *DriftDetector) processMessage(raw []byte) error {
   257→	var obs map[string]float64
   258→	if err := json.Unmarshal(raw, &obs); err != nil {
   259→		return fmt.Errorf("decode feature vector: %w", err)
   260→	}
   261→
   262→	for fname, v := range obs {
   263→		win, ok := d.windows[fname]
   264→		if !ok {
   265→			continue // unknown feature
   266→		}
   267→		win.add(v)
   268→		if win.ready(d.conf.WindowSize) {
   269→			counts := win.pop()
   270→			psi, err := computePSI(counts, win.ref.Expected)
   271→			if err != nil {
   272→				d.log.Warn("psi computation failed", "feature", fname, "err", err)
   273→				continue
   274→			}
   275→			if psi >= d.conf.PSIThreshold {
   276→				alert := DriftAlert{
   277→					Feature:    fname,
   278→					PSI:        psi,
   279→					Threshold:  d.conf.PSIThreshold,
   280→					WindowSize: d.conf.WindowSize,
   281→					Timestamp:  time.Now().UTC(),
   282→				}
   283→				if err := d.publishAlert(alert); err != nil {
   284→					d.log.Error("publish alert failed", "feature", fname, "err", err)
   285→				} else {
