   316→// computePSI returns the population stability index.
   317→// counts and expected must have identical length.
   318→func computePSI(counts []int, expected []float64) (float64, error) {
   319→	if len(counts) != len(expected) {
   320→		return 0, errors.New("mismatched lengths")
   321→	}
   322→	total := 0
   323→	for _, c := range counts {
   324→		total += c
   325→	}
   326→	if total == 0 {
   327→		return 0, errors.New("empty window")
   328→	}
