   117→// DriftMonitor consumes MetricsPayload, computes drift, and triggers retrain.
   118→type DriftMonitor struct {
   119→	cfg     DriftMonitorConfig
   120→	reader  *kafka.Reader
   121→	writer  *kafka.Writer
   122→	ctx     context.Context
   123→	cancel  context.CancelFunc
   124→	wg      sync.WaitGroup
   125→	metrics struct {
   126→		driftGauge         *prometheus.GaugeVec
   127→		retrainCounter     *prometheus.CounterVec
   128→		processingDuration prometheus.Histogram
