   132→// NewDriftMonitor constructs and validates a DriftMonitor.
   133→func NewDriftMonitor(cfg DriftMonitorConfig) (*DriftMonitor, error) {
   134→	if err := cfg.Validate(); err != nil {
   135→		return nil, err
   136→	}
   137→
   138→	// Prometheus instrumentation objects.
   139→	dm := &DriftMonitor{cfg: cfg}
   140→	dm.ctx, dm.cancel = context.WithCancel(context.Background())
   141→	dm.metrics.driftGauge = prometheus.NewGaugeVec(
   142→		prometheus.GaugeOpts{
   143→			Namespace: cfg.InstrumentationNS,
   144→			Subsystem: "drift_monitor",
   145→			Name:      "psi",
   146→			Help:      "Population Stability Index per model",
   147→		},
   148→		[]string{"model_id"},
   149→	)
   150→	dm.metrics.retrainCounter = prometheus.NewCounterVec(
   151→		prometheus.CounterOpts{
   152→			Namespace: cfg.InstrumentationNS,
   153→			Subsystem: "drift_monitor",
   154→			Name:      "retrain_total",
   155→			Help:      "Total retrain events triggered",
   156→		},
   157→		[]string{"model_id"},
   158→	)
   159→	dm.metrics.processingDuration = prometheus.NewHistogram(
   160→		prometheus.HistogramOpts{
   161→			Namespace: cfg.InstrumentationNS,
   162→			Subsystem: "drift_monitor",
   163→			Name:      "processing_seconds",
   164→			Help:      "Time spent processing metric messages",
   165→			Buckets:   prometheus.DefBuckets,
   166→		},
   167→	)
