   175→	dm.reader = kafka.NewReader(kafka.ReaderConfig{
   176→		Brokers:        cfg.BootstrapServers,
   177→		GroupID:        cfg.ConsumerGroupID,
   178→		Topic:          cfg.MetricsTopic,
   179→		MinBytes:       10e3,  // 10KB
   180→		MaxBytes:       10e6,  // 10MB
   181→		MaxWait:        250 * time.Millisecond,
   182→		CommitInterval: 0, // synchronous commit
   183→	})
