   203→	}
   204→}
   205→
   206→// Stop shuts down the monitor gracefully.
   207→func (d *DriftMonitor) Stop(ctx context.Context) error {
   208→	if d.cfg.Logger != nil {
   209→		d.cfg.Logger.Infof("DriftMonitor shutting down")
   210→	}
   211→	d.cancel()
   212→	stopped := make(chan struct{})
   213→	go func() {
   214→		d.wg.Wait()
   215→		stopped <- struct{}{}
   216→	}()
