   223→		return fmt.Errorf("reader close: %w", err)
   224→	}
   225→	if err := d.writer.Close(); err != nil {
   226→		return fmt.Errorf("writer close: %w", err)
   227→	}
   228→	return nil
   229→}
   230→
   231→// workerLoop consumes messages and processes them.
   232→func (d *DriftMonitor) workerLoop(workerID int) {
   233→	defer d.wg.Done()
   234→	for {
   235→		m, err := d.reader.ReadMessage(d.ctx)
   236→		if err != nil {
   237→			if errors.Is(err, context.Canceled) {
   238→				return
   239→			}
   240→			if d.cfg.Logger != nil {
   241→				d.cfg.Logger.Errorf("worker %d read error: %v", workerID, err)
   242→			}
   243→			continue
   244→		}
