   257→		return fmt.Errorf("unmarshal MetricsPayload: %w", err)
   258→	}
   259→
   260→	// Compute aggregate drift across all features.
   261→	var psiSum float64
   262→	var count int
   263→	for _, bucket := range payload.FeatureDrifts {
   264→		psiSum += populationStabilityIndex(bucket.Expected, bucket.Observed)
