   266→	}
   267→	if count == 0 {
   268→		return errors.New("empty feature drift data")
   269→	}
   270→	avgPSI := psiSum / float64(count)
   271→	d.metrics.driftGauge.WithLabelValues(payload.ModelID).Set(avgPSI)
   272→
   273→	if d.cfg.Logger != nil {
   274→		d.cfg.Logger.Debugf("model=%s version=%s avgPSI=%.4f", payload.ModelID, payload.ModelVersion, avgPSI)
   275→	}
   276→
   277→	// Determine if retrain is needed.
   278→	if avgPSI >= d.cfg.DriftThreshold {
   279→		req := RetrainRequest{
   280→			ModelID:        payload.ModelID,
   281→			CurrentVersion: payload.ModelVersion,
   282→			DriftMagnitude: avgPSI,
   283→			TriggeredAt:    time.Now().UnixMilli(),
   284→			Reason:         fmt.Sprintf("PSI above threshold (%.2f >= %.2f)", avgPSI, d.cfg.DriftThreshold),
   285→			CorrelationID:  fmt.Sprintf("%s_%d", payload.ModelID, m.Offset),
   286→		}
   287→		b, _ := json.Marshal(&req)
   288→		msg := kafka.Message{
   289→			Key:   []byte(req.ModelID),
   290→			Value: b,
   291→		}
   292→		if err := d.writer.WriteMessages(d.ctx, msg); err != nil {
   293→			return fmt.Errorf("write retrain request: %w", err)
   294→		}
   295→		d.metrics.retrainCounter.WithLabelValues(req.ModelID).Inc()
   296→		if d.cfg.Logger != nil {
   297→			d.cfg.Logger.Infof("Triggered retrain for %s (PSI=%.3f)", req.ModelID, avgPSI)
   298→		}
   299→	}
   300→	return nil
   301→}
   302→
   303→// populationStabilityIndex computes PSI between expected and observed histograms.
   304→// It returns math.NaN() if arrays have different sizes or contain invalid values.
   305→//
   306→// Note: In production, you might move this to its own math/stats package and
   307→// use higher precision numerics.  Here we apply a pragmatic approach.
   308→func populationStabilityIndex(expected, observed []float64) float64 {
   309→	if len(expected) != len(observed) || len(expected) == 0 {
   310→		return math.NaN()
   311→	}
   312→
   313→	var psi float64
   314→	for i, e := range expected {
   315→		o := observed[i]
   316→		if e <= 0 || o <= 0 {
   317→			continue // skip zero buckets to avoid divide-by-zero/log
   318→		}
   319→		psi += (o - e) * math.Log(o/e)
   320→	}
   321→	return psi
   322→}
