    29→
    30→import (
    31→	"container/heap"
    32→	"context"
    33→	"errors"
    34→	"log"
    35→	"regexp"
    36→	"strings"
    37→	"sync"
    38→	"time"
    39→)
    40→
    41→// ---------- Public Domain Model ---------- //
    42→
    43→// SocialEvent is the canonical payload broadcast on the platform bus.
    44→// We only care about Body text for trend detection, but we keep the
    45→// whole struct around for context / future feature expansion.
    46→type SocialEvent struct {
    47→	EventID   string            `json:"event_id"`
    48→	Timestamp time.Time         `json:"ts"`
    49→	Body      string            `json:"body"`
    50→	Metadata  map[string]string `json:"meta,omitempty"`
