    53→// Trend holds the aggregated count for a single token.
    54→type Trend struct {
    55→	Term  string
    56→	Count int
    57→}
    58→
    59→// TrendSurferConfig exposes tunables for runtime configuration.
    60→type TrendSurferConfig struct {
    61→	WindowSize       time.Duration // Sliding window length (e.g. 10m)
    62→	BucketInterval   time.Duration // Granularity within the window (e.g. 1m)
