    82→
    83→// ---------- TrendSurfer Implementation ---------- //
    84→
    85→type TrendSurfer struct {
    86→	cfg TrendSurferConfig
    87→	bus EventBus
    88→
    89→	callbackMu sync.RWMutex
    90→	callbacks  []func([]Trend)
    91→
    92→	// buckets is a ring buffer of token->count maps keyed by time bucket.
    93→	buckets []map[string]int
    94→	head    int // index of the most-recent bucket
    95→
    96→	// aggregate is the merged view across the sliding window.
    97→	aggregate map[string]int
    98→
    99→	// prevTopK keeps the last emitted set for drift detection.
   100→	prevTopK map[string]struct{}
