   104→
   105→// NewTrendSurfer constructs a ready-to-start TrendSurfer.
   106→func NewTrendSurfer(cfg TrendSurferConfig, bus EventBus) (*TrendSurfer, error) {
   107→	if cfg.WindowSize <= 0 {
   108→		return nil, errors.New("window size must be > 0")
   109→	}
   110→	if cfg.BucketInterval <= 0 {
   111→		return nil, errors.New("bucket interval must be > 0")
   112→	}
   113→	if cfg.WindowSize%cfg.BucketInterval != 0 {
   114→		return nil, errors.New("window size must be divisible by bucket interval")
   115→	}
   116→	if cfg.TopK <= 0 {
   117→		cfg.TopK = 10
   118→	}
   119→	if cfg.MinTokenLength <= 0 {
   120→		cfg.MinTokenLength = 3
   121→	}
   122→	if cfg.DriftThreshold <= 0 {
   123→		cfg.DriftThreshold = 0.3
   124→	}
   125→	if cfg.Logger == nil {
   126→		cfg.Logger = log.Default()
   127→	}
   128→
   129→	bucketCount := int(cfg.WindowSize / cfg.BucketInterval)
   130→	buckets := make([]map[string]int, bucketCount)
   131→	for i := range buckets {
   132→		buckets[i] = make(map[string]int)
   133→	}
   134→
   135→	return &TrendSurfer{
   136→		cfg:       cfg,
   137→		bus:       bus,
   138→		buckets:   buckets,
   139→		aggregate: make(map[string]int),
   140→		prevTopK:  make(map[string]struct{}),
   141→	}, nil
   142→}
   143→
   144→// Start launches the processing loop. The call is non-blocking; callers should
   145→// cancel the context to terminate the surfer.
   146→func (ts *TrendSurfer) Start(ctx context.Context, topic string) error {
   147→	eventCh, err := ts.bus.Subscribe(ctx, topic)
   148→	if err != nil {
   149→		return err
   150→	}
   151→
   152→	go ts.run(ctx, eventCh)
