   154→}
   155→
   156→// RegisterCallback allows clients to be notified when new trends surface.
   157→func (ts *TrendSurfer) RegisterCallback(fn func([]Trend)) {
   158→	ts.callbackMu.Lock()
   159→	defer ts.callbackMu.Unlock()
   160→	ts.callbacks = append(ts.callbacks, fn)
   161→}
