   168→	return computeTopK(ts.aggregate, ts.cfg.TopK)
   169→}
   170→
   171→// ---------- Private Methods ---------- //
   172→
   173→func (ts *TrendSurfer) run(ctx context.Context, events <-chan *SocialEvent) {
   174→	ticker := time.NewTicker(ts.cfg.BucketInterval)
   175→	defer ticker.Stop()
   176→
