   226→		ts.emit(top)
   227→	}
   228→}
   229→
   230→func (ts *TrendSurfer) hasDrifted(top []Trend) bool {
   231→	curSet := make(map[string]struct{}, len(top))
   232→	for _, t := range top {
   233→		curSet[t.Term] = struct{}{}
   234→	}
   235→
   236→	overlap := 0
   237→	for term := range curSet {
   238→		if _, ok := ts.prevTopK[term]; ok {
   239→			overlap++
   240→		}
   241→	}
   242→	sharedRatio := float64(overlap) / float64(len(curSet))
   243→	drifted := sharedRatio < (1.0 - ts.cfg.DriftThreshold)
   244→
   245→	if drifted {
   246→		ts.prevTopK = curSet
   247→	}
   248→	return drifted
   249→}
   250→
   251→func (ts *TrendSurfer) emit(top []Trend) {
   252→	ts.cfg.Logger.Printf("New trend set detected (top-%d): %+v\n", ts.cfg.TopK, top)
   253→
   254→	ts.callbackMu.RLock()
   255→	defer ts.callbackMu.RUnlock()
   256→	for _, fn := range ts.callbacks {
   257→		// Fire callbacks asynchronously to avoid blocking.
   258→		go func(f func([]Trend)) {
   259→			defer func() {
   260→				if r := recover(); r != nil {
   261→					ts.cfg.Logger.Printf("trend callback panic: %v", r)
   262→				}
   263→			}()
   264→			f(top)
   265→		}(fn)
   266→	}
   267→}
   268→
   269→// ---------- Helpers ---------- //
   270→
   271→// Simple tokenizer based on regexp split.
   272→// Production systems might use a proper NLP package but this keeps the module
   273→// self-contained.
   274→var nonAlpha = regexp.MustCompile(`[^\p{L}]+`)
   275→
   276→func tokenize(text string, cfg TrendSurferConfig) []string {
   277→	if cfg.CaseInsensitive {
   278→		text = strings.ToLower(text)
   279→	}
   280→
   281→	parts := nonAlpha.Split(text, -1)
   282→	out := make([]string, 0, len(parts))
   283→
   284→	for _, p := range parts {
   285→		if p == "" || len(p) < cfg.MinTokenLength {
   286→			continue
   287→		}
   288→		if _, stop := cfg.StopWords[p]; stop {
   289→			continue
   290→		}
   291→		out = append(out, p)
   292→	}
   293→	return out
   294→}
   295→
   296→// ---------- Top-K Heap ---------- //
   297→
   298→type kv struct {
   299→	key   string
   300→	value int
   301→}
   302→
   303→type minHeap []kv
   304→
   305→func (h minHeap) Len() int            { return len(h) }
   306→func (h minHeap) Less(i, j int) bool  { return h[i].value < h[j].value }
   307→func (h minHeap) Swap(i, j int)       { h[i], h[j] = h[j], h[i] }
   308→func (h *minHeap) Push(x interface{}) { *h = append(*h, x.(kv)) }
   309→func (h *minHeap) Pop() interface{} {
   310→	old := *h
   311→	n := len(old)
   312→	item := old[n-1]
   313→	*h = old[:n-1]
   314→	return item
   315→}
   316→
   317→// computeTopK returns the K largest counts in O(n log k).
   318→func computeTopK(m map[string]int, k int) []Trend {
   319→	h := &minHeap{}
   320→	heap.Init(h)
   321→
   322→	for term, count := range m {
   323→		if h.Len() < k {
   324→			heap.Push(h, kv{term, count})
   325→		} else if count > (*h)[0].value {
   326→			heap.Pop(h)
   327→			heap.Push(h, kv{term, count})
   328→		}
   329→	}
   330→
   331→	// Extract in reverse order (largest first).
   332→	res := make([]Trend, h.Len())
   333→	for i := len(res) - 1; i >= 0; i-- {
   334→		item := heap.Pop(h).(kv)
   335→		res[i] = Trend{Term: item.key, Count: item.value}
   336→	}
   337→	return res
   338→}

